text:
&-operation {
  width: @size-6;
  width: var(--am-operation-icon-width, @size-6);
  height: @size-6;
  height: var(--am-operation-icon-height, @size-6);
  overflow: hidden;
  text-align: center;
  line-height: @size-6;
  line-height: var(--am-title-operation-lineHeight, @size-6);
  margin-left: @h-spacing-standard;
  margin-left: var(--am-title-operation-marginLeft, @h-spacing-standard);
  &-icon {
    font-size: @icon-size-xs;
    font-size: var(--am-title-operation-icon-size, @icon-size-xs);
    color: @color-text-weak;
    color: var(--am-title-operation-icon-color, @color-text-weak);
  }
}

&-input {
  height: @size-6;
  height: var(--am-stepper-input-size, @size-6);
  padding: 0;
  margin: 0 @v-spacing-standard;
  margin: 0 var(--am-stepper-input-marginLR, v-spacing-standard);
  line-height: @size-6;
  line-height: var(--am-stepper-input-size, @size-6);
  text-align: center;
  font-size: @font-size-subtitle;
  font-size: var(--am-stepper-input-fontSize, @font-size-subtitle);
  color: @color-text-title;
  color: var(--am-stepper-input-color, @color-text-title);
  border: 0 none;
  background-color: transparent;
  transform: translate(0, -1px);
  &-hide {
    visibility: hidden;
  }
}

&&-selected {
  && {
    background: rgba(22, 119, 255, 10%);
    color: var(--adm-color-text);
  }

  & .adm-calendar-picker-view-cell-top,
  & .adm-calendar-picker-view-cell-bottom {
    color: var(--adm-color-white);
  }

  &&-begin {
    background: var(--adm-color-primary);
    color: var(--adm-color-white);
    border-top-left-radius: 4px;
    border-bottom-left-radius: 4px;
  }

  &&-end {
    background: var(--adm-color-primary);
    color: var(--adm-color-white);
    border-top-right-radius: 4px;
    border-bottom-right-radius: 4px;
  }
}

& when not (@critical) {
    .button-close {
        &:extend(.breeze-button-close all);
    }

    .shadow-sm { box-shadow: @shadow-sm; }
    .shadow { box-shadow: @shadow; }
    .shadow-md { box-shadow: @shadow-md; }
    .shadow-lg { box-shadow: @shadow-lg; }
    .shadow-xl { box-shadow: @shadow-xl; }
    .shadow-2xl { box-shadow: @shadow-2xl; }
    .shadow-sm-around { box-shadow: @shadow-sm-around; }
    .shadow-around { box-shadow: @shadow-around; }
    .shadow-md-around { box-shadow: @shadow-md-around; }
    .shadow-lg-around { box-shadow: @shadow-lg-around; }
    .shadow-xl-around { box-shadow: @shadow-xl-around; }
    .shadow-2xl-around { box-shadow: @shadow-2xl-around; }
}

&-card {
  background: linear-gradient(180deg, var(--r-surface) 0%, var(--r-surface-2) 100%);
  border: 1px solid var(--r-line);
  padding: 18px 18px 16px;
  position: relative;
  overflow: hidden;
  transition: border-color .15s, box-shadow .15s;

  &:hover {
    border-color: var(--r-accent);
    box-shadow: 0 0 0 1px var(--r-accent-soft), 0 0 24px -8px var(--r-accent);
  }

  &::before {
    content: '';
    position: absolute; top: 0; right: 0;
    width: 16px; height: 16px;
    background: var(--r-bg);
    clip-path: polygon(100% 0, 0 0, 100% 100%);
    border-left: 1px solid var(--r-line);
    border-bottom: 1px solid var(--r-line);
  }

  &::after {
    content: '';
    position: absolute; inset: 0;
    background: repeating-linear-gradient(180deg, transparent 0 3px, var(--r-scanline-2) 3px 4px);
    pointer-events: none;
  }
}

&-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 8px;

  li {
    display: flex;
    align-items: center;
    gap: 10px;
    font-family: 'JetBrains Mono', monospace;
    font-size: 11px;
    letter-spacing: 0.08em;
    color: var(--r-text);
  }

  .pip {
    width: 10px;
    height: 10px;
    transform: rotate(45deg);
    flex: 0 0 10px;
    box-shadow: 0 0 8px currentColor;

    &.legendary { background: var(--r-gold);  color: var(--r-gold); }
    &.epic      { background: var(--r-epic);  color: var(--r-epic); }
    &.rare      { background: var(--r-rare);  color: var(--r-rare); }
    &.common    { background: var(--r-common); color: var(--r-common); box-shadow: none; }
  }
}

@-webkit-keyframes browseIn {
  0% {
    -webkit-transform: scale(0.8) translateZ(0px);
            transform: scale(0.8) translateZ(0px);
    z-index: -1;
  }
  10% {
    -webkit-transform: scale(0.8) translateZ(0px);
            transform: scale(0.8) translateZ(0px);
    z-index: -1;
    opacity: 0.7;
  }
  80% {
    -webkit-transform: scale(1.05) translateZ(0px);
            transform: scale(1.05) translateZ(0px);
    opacity: 1;
    z-index: 999;
  }
  100% {
    -webkit-transform: scale(1) translateZ(0px);
            transform: scale(1) translateZ(0px);
    z-index: 999;
  }
}

@keyframes browseIn {
  0% {
    -webkit-transform: scale(0.8) translateZ(0px);
            transform: scale(0.8) translateZ(0px);
    z-index: -1;
  }
  10% {
    -webkit-transform: scale(0.8) translateZ(0px);
            transform: scale(0.8) translateZ(0px);
    z-index: -1;
    opacity: 0.7;
  }
  80% {
    -webkit-transform: scale(1.05) translateZ(0px);
            transform: scale(1.05) translateZ(0px);
    opacity: 1;
    z-index: 999;
  }
  100% {
    -webkit-transform: scale(1) translateZ(0px);
            transform: scale(1) translateZ(0px);
    z-index: 999;
  }
}

&.flat.flat {
  :is(.alert, .article-note) {
    border-color: fade(@amber, @fade5);
    background-color: fade(@amber, @fade4);
    color: if(@is-night, lighten(@amber, @fade3), darken(@amber, @fade3));

    h4 {
      color: unset;
    }
  }
  each(@colors-alert, {
    .alert-@{key} {
      border-color: fade(@value, @fade5);
      background-color: fade(@value, @fade4);
      color: if(@is-night, lighten(@value, @fade3), darken(@value, @fade3));
    }
    .text-@{key} {
      color: if(@is-night, lighten(@value, 5%), darken(@value, 10%));
    }
  });
}

body {
	font-weight: 500;
	color: var(--body-color, #7b7b7d);
	background-color: var(--body-bg-color);
	letter-spacing: 0.05em;
	overflow-x: hidden;
	margin: 0;
	margin-right: calc(100% - 100vw);
	padding: 10px;
	height: 100vh;
	scroll-behavior: smooth;
	-webkit-font-smoothing: antialiased;

	&::before {
		content: "";
		position: fixed;
		left: 10px;
		top: 10px;
		width: calc(100% - 20px);
		height: calc(100% - 20px);
		z-index: 9999;
		pointer-events: none;
		box-shadow: 0 0 0 20px var(--body-bg-color);
		border-radius: 10px;
		outline: var(--body-bg-color) solid 10px;
	}
}

&&__stripe,
  &&__stripe-saas {
    .@{grid-prefix-cls}-body__row {
      // 支持所有行 hover 背景颜色
      &:not(.row__hover) {
        &:nth-child(2n) {
          background-color: var(--tiny-color-fill-8, #f4f6fb);
        }

        &.row__current {
          @apply bg-color-info-primary-subtler;
        }
      }

      &.row__selected {
        &:nth-child(2n) {
          @apply bg-color-info-primary-subtler;
        }

        &:nth-child(2n + 1) {
          background-color: var(--tiny-color-fill-8, #f4f6fb);
        }
      }
    }

    &.mark-insert {
      .@{grid-prefix-cls}-body__row.row__new {
        @apply bg-color-bg-2;
      }
    }
  }

&--inline {
  .@{form-item-prefix-cls},
  .@{form-item-prefix-cls}__content {
    @apply inline-block;
    @apply align-top;
  }

  .@{form-item-prefix-cls} {
    @apply mr-18;
  }

  .@{form-item-prefix-cls}__label {
    @apply float-none;
    @apply inline-block;
  }

  .@{form-prefix-cls}--label-top .@{form-item-prefix-cls}__content {
    @apply block;
  }

  .@{form-item-prefix-cls}--small .@{form-item-prefix-cls}__form-inline--small {
    @apply h-7 leading-7;
  }

  .@{form-item-prefix-cls}--mini .@{form-item-prefix-cls}__form-inline--mini {
    @apply h-6 leading-6;
  }

  .@{form-item-prefix-cls}--medium .@{form-item-prefix-cls}__form-inline--medium {
    @apply h-8 leading-8;
  }
}

&.size__small,
    &.size__mini {
      @apply text-xs;

      .@{modal-prefix-cls}__box {
        @apply ~'py-1.5' px-0;
      }

      .@{modal-prefix-cls}__body {
        @apply ~'pt-1 pr-3.5 pb-2.5 pl-3.5';
      }

      .@{modal-prefix-cls}__footer {
        @apply ~'pt-1 pr-3.5 pb-2 pl-3.5';
      }

      .@{modal-prefix-cls}__header {
        @apply text-sm;
        @apply pt-6 px-6 pb-0;
      }

      .@{modal-prefix-cls}__zoom-btn,
      .@{modal-prefix-cls}__close-btn {
        @apply text-base;
        @apply ~'top-2.5';
      }
    }

&__toggle-button {
  position: absolute;
  cursor: pointer;
  right: 0;
  top: 50%;
  transform: translateX(50%) translateY(-50%);
  z-index: 9;
  width: 24px;
  height: 24px;
  border-radius: 50%;
  font-size: 18px;
  line-height: 18px;
  background-color: var(--tv-TreeMenu-toggle-button-background-color);
  box-shadow: 0 2px 4px 0px rgba(0, 0, 0, 0.06);
  border: 1px solid var(--tv-TreeMenu-border-color);

  .tiny-svg {
    margin-left: 2px;
    margin-top: 2px;
    fill: var(--tv-TreeMenu-collapse-icon-fill-color);
    font-size: 16px;

    &:hover {
      fill: var(--tv-TreeMenu-collapse-icon-hover-color);
    }

    &:focus {
      fill: var(--tv-TreeMenu-collapse-icon-hover-color);
    }
  }
}

ul {
  li {
    display: block;
    color: var(--tv-Floatbar-list-text-color);
    font-size: var(--tv-Floatbar-font-size);
    min-width: 104px;
    min-height: 32px;
    line-height: 32px;
    text-align: center;
    margin: var(--tv-Floatbar-list-margin-x) 0;
    padding: 0 24px;

    &:hover {
      background: var(--tv-Floatbar-list-bg-color-hover)
    }

    a {
      width: 100%;
      height: 100%;
      color: var(--tv-Floatbar-list-text-color);
      cursor: pointer;
      outline: none;

      &:hover,
      &:focus {
        color: var(--tv-Floatbar-list-text-color-hover);
        text-decoration: none;
      }
    }
  }
}

&.size__medium {
  .@{grid-prefix-cls}-header__column,
  .@{grid-prefix-cls}-body__column,
  .@{grid-prefix-cls}-footer__column {
    .MediumColumnHeight();

    &:not(.col__ellipsis) {
      @apply ~'py-0.5' px-2;
    }
  }

  .@{grid-prefix-cls}-loading {
    .@{grid-prefix-cls}__spinner {
      width: 50px;
      height: 50px;
    }
  }

  .@{grid-prefix-cls}-default-input,
  .@{grid-prefix-cls}-default-textarea,
  .@{grid-prefix-cls}-default-select,
  .@{grid-prefix-cls}-input__wrapper {
    .MediumColumnHeight();
  }

  .@{grid-header-prefix-cls}__column {
    .@{grid-prefix-cls}-resizable {
      @apply h-4;
    }
  }
}

li {
  display: block;
  color: var(--tv-Floatbar-list-text-color);
  font-size: var(--tv-Floatbar-font-size);
  min-width: 104px;
  min-height: 32px;
  line-height: 32px;
  text-align: center;
  margin: var(--tv-Floatbar-list-margin-x) 0;
  padding: 0 24px;

  &:hover {
    background: var(--tv-Floatbar-list-bg-color-hover)
  }

  a {
    width: 100%;
    height: 100%;
    color: var(--tv-Floatbar-list-text-color);
    cursor: pointer;
    outline: none;

    &:hover,
    &:focus {
      color: var(--tv-Floatbar-list-text-color-hover);
      text-decoration: none;
    }
  }
}

&.is-error,
      &.is-warning,
      &.is-success,
      &.is-info {
        @apply bg-color-bg-1;
        @apply shadow-lg;
        overflow: unset;

        &[x-placement^='right'] {
          > .popper__arrow {
            @apply border-r-color-bg-1;

            &::after {
              @apply border-r-color-bg-1;
            }
          }
        }

        &[x-placement^='left'] {
          > .popper__arrow {
            @apply border-l-color-bg-1;

            &::after {
              @apply border-l-color-bg-1;
            }
          }
        }
      }

&.size__small,
    &.size__mini {
      @apply text-xs;

      .@{grid-modal-prefix-cls}__box {
        @apply ~'py-1.5' px-0;
      }

      .@{grid-modal-prefix-cls}__body {
        @apply ~'pt-1 pr-3.5 pb-2.5 pl-3.5';
      }

      .@{grid-modal-prefix-cls}__footer {
        @apply ~'pt-1 pr-3.5 pb-2 pl-3.5';
      }

      .@{grid-modal-prefix-cls}__header {
        @apply text-sm;
        @apply pt-6 px-6 pb-0;
      }

      .@{grid-modal-prefix-cls}__zoom-btn,
      .@{grid-modal-prefix-cls}__close-btn {
        @apply text-base;
        @apply ~'top-2.5';
      }
    }

&__nav-container {
  position: relative;

  &.@{prefix}-is-top::after {
    .bar-track-pseudo(100%, 1px, auto, auto, 0, 0);
  }

  &.@{prefix}-is-bottom::after {
    .bar-track-pseudo(100%, 1px, 0, auto, auto, 0);
  }

  &.@{prefix}-is-left::after {
    .bar-track-pseudo(1px, 100%, 0, 0);
  }

  &.@{prefix}-is-right::after {
    .bar-track-pseudo(1px, 100%, 0, auto, auto, 0);
  }

  &.@{prefix}-is-addable {
    margin-right: @tab-btn-width;
  }

  &.@{prefix}-tabs__nav--card {
    // border-bottom: 1px solid @tab-default-stroke;

    &::after {
      content: '';
      background-color: transparent;
    }
  }
}

p,
    ul:not(.vh-vhMusic ul, .vh-comment ul),
    ol:not(.vh-vhMusic ol, .vh-comment ol) {
      padding: 0.618rem 0;
      font-size: 0.9375rem;
      line-height: 1.6;

      li {
        color: var(--vh-font-66);
        font-size: 0.875rem;
        line-height: 1.6;
      }

      // 其下面的 a 标签样式
      a {
        color: var(--vh-font-56);
        box-shadow: inset 0 -.12rem var(--vh-main-color);
        transition: box-shadow .2s ease-in-out, color .2s ease-in-out;

        &:hover {
          box-shadow: inset 0 -1.5rem var(--vh-main-color-28);
        }
      }

      // 其下面的code标签样式
      code {
        background-color: var(--vh-font-16);
        padding: .125rem .375rem;
        font-size: 0.8125rem;
      }
    }
